INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (2, '历届世界杯冠军都是谁', 21.068, 72, 44, '2026-06-08 06:32:40', '2026-07-15 11:23:04', '2026-07-12 12:00:00', 'mid_high', 'growth', 0.9, 0.05, 0.9, 0.05, 0.0, '当前事件报道数量持续增加，公众关注度快速提升，处于成长期。', 0.4, 0.333, 0.267, '["微博", "新浪新闻", "澎湃新闻", "知乎"]', '7月10日凌晨，美加墨世界杯1/4决赛就将拉开大幕。法国对阵摩洛哥的赛前，法国队心心念念的黄牌申诉并未得到国际足联的回应，面对本场执法的阿根廷裁判组，主教练德尚并不在意，他清楚对手只有摩洛哥。创造历史的挪威队则在对阵英格兰前，就要经历严峻的挑战——继哥伦比亚队遭遇流感病毒的袭扰后，这支北欧球队同样被病毒困扰。', '法国、英格兰、西班牙', '美加墨世界杯32强对阵图。', '["贝林厄姆", "亚马尔", "凯恩", "哈兰德", "赫尔"]', '{"credibility_score": 0.705, "official_ratio": 0.722, "verified_ratio": 0.861, "plain_user_ratio": 0.139, "verification_dist": {"官方平台": 0.722, "普通用户": 0.139, "认证个人": 0.069, "头部认证个人": 0.056, "认证机构": 0.014}, "factors": ["high_duplicate_rate", "well_sourced"]}', '{"key_nodes": [{"role": "初始爆料", "author": "独角龙", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-06-08T06:32:40", "influence": 2.3, "title": "责任不在他。而是巴萨方面，一直要坚持自己的所谓风格，不肯向对手（尤其是皇马，拜仁"}, {"role": "首次官方媒体介入", "author": "澎湃新闻", "platform": "澎湃新闻", "verification_type": "官方平台", "publish_time": "2026-06-28T00:00:00", "influence": 0.0, "title": "世界杯首次1/16决赛，我们看什么？_运动家_澎湃新闻-The Paper"}, {"role": "传播高峰", "author": "王玮晨", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-12T08:12:18", "influence": 1291.3, "title": "这场赛后可能还有争议。 贝林厄姆打入的那粒扳平进球，挪威守门员开大脚，球先击中了"}, {"role": "首次大V发声", "author": "欧洲时报", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-12T20:49:53", "influence": 2.7, "title": "【“法国队水平很高……但没有一名法国球员”，西班牙前首相发表种族主义言论惹众怒】"}], "top_influencers": [{"author": "王玮晨", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-12T08:12:18", "influence": 1291.3, "repost_count": 61, "like_count": 3401, "comment_count": 420, "title": "这场赛后可能还有争议。 贝林厄姆打入的那粒扳平进球，挪威守门员开大脚，球先击中了"}, {"author": "Njone足球梦想", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-12T14:55:32", "influence": 90.9, "repost_count": 0, "like_count": 203, "comment_count": 60, "title": "世界杯四强凑齐了——法国、西班牙、英格兰、阿根廷。国际足联排名前四，一个不差。挪"}, {"author": "在大笑的榴莲", "platform": "微博", "verification_type": "头部认证个人", "publish_time": "2026-07-13T09:59:27", "influence": 60.0, "repost_count": 0, "like_count": 90, "comment_count": 66, "title": "#前西班牙首相称法国队没法国球员#前西班牙首相拉霍伊那句“法国队没法国球员”，听"}, {"author": "英仙说", "platform": "知乎", "verification_type": "认证个人", "publish_time": "2026-07-12T12:34:49", "influence": 51.4, "repost_count": 0, "like_count": 128, "comment_count": 26, "title": "其实英阿的历史恩怨，早就清了。头一波，是马岛战争+86世界杯。带英赢了热战，输了"}, {"author": "皮雷耶斯泽斯尼", "platform": "知乎", "verification_type": "认证个人", "publish_time": "2026-07-12T12:31:21", "influence": 35.8, "repost_count": 0, "like_count": 101, "comment_count": 11, "title": "四强完美符合了抽签时的“剧本”。四大种子如愿会师半决赛。我肯定更看好法国和西班牙"}], "platform_chain": {"nodes": [{"name": "知乎", "count": 11, "first_seen": "2026-06-08T06:32:40"}, {"name": "澎湃新闻", "count": 22, "first_seen": "2026-06-28T00:00:00"}, {"name": "新浪新闻", "count": 26, "first_seen": "2026-07-11T11:27:00"}, {"name": "微博", "count": 9, "first_seen": "2026-07-12T08:12:18"}], "links": [{"source": "知乎", "target": "澎湃新闻", "value": 22}, {"source": "澎湃新闻", "target": "新浪新闻", "value": 26}, {"source": "新浪新闻", "target": "微博", "value": 9}]}}', '2026-07-15 22:17:29', '2026-07-15 22:17:29');
