INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (5, '小球迷演绎阿根廷vs埃及', 9.274, 108, 86, '2026-07-03 17:40:02', '2026-07-14 19:38:10', '2026-07-08 12:00:00', 'mid', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.568, 0.233, 0.199, '["微博", "新浪新闻", "澎湃新闻", "知乎"]', '7月13日消息，尽管在本届世界杯一路闯入四强，但是卫冕冠军阿根廷的晋级之路，伴随着巨大的争议声音。从开赛以来到跻身四强，阿根廷队在6场比赛中，出现了6次重大争议判罚。巧合的是，这几次争议判罚中，阿根廷队几乎都是获益的一方。', '埃及、瑞士、法国', '北京时间7月8日上午，据西班牙《阿斯报》等媒体报道称，埃及足协已向国际足联提交了一份完整的书面申诉，矛头直指执法埃及队与阿根廷队1/8决赛的法国主裁判勒泰西耶及其全套VAR裁判组。', '["萨拉赫", "哈桑", "恩佐", "科里纳", "阿尔瓦雷"]', '{"credibility_score": 0.344, "official_ratio": 0.194, "verified_ratio": 0.63, "plain_user_ratio": 0.37, "verification_dist": {"普通用户": 0.37, "认证个人": 0.333, "官方平台": 0.194, "认证机构": 0.056, "头部认证个人": 0.046}, "factors": ["high_duplicate_rate"]}', '{"key_nodes": [{"role": "初始爆料", "author": "格子军团", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-03T17:40:02", "influence": 0.3, "title": "周五086 世界杯 澳大利亚vs埃及方向：让胜年龄： 11岁 21岁周五087 "}, {"role": "首次大V发声", "author": "直播吧", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-08T02:14:19", "influence": 3959.9, "title": "埃及全队投诉，阿根廷进球前，萨拉赫在阿根廷禁区倒地，埃及工作人员被红牌罚下。主帅"}, {"role": "首次官方媒体介入", "author": "澎湃新闻", "platform": "澎湃新闻", "verification_type": "官方平台", "publish_time": "2026-07-08T11:25:00", "influence": 0.0, "title": "指责主裁双标，埃及足协就争议判罚向国际足联提出申诉_运动家_澎湃新闻-The P"}, {"role": "传播高峰", "author": "咪咕体育", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-09T13:22:41", "influence": 21215.2, "title": "#FIFA认定阿根廷进球判罚正确##FIFA认定埃及进球被取消判罚正确# 对于阿"}], "top_influencers": [{"author": "咪咕体育", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-09T13:22:41", "influenc