INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (7, '世界杯决赛首次增设中场秀', 7.878, 9, 0, '2026-07-14 11:14:29', '2026-07-15 17:54:00', '2026-07-15 12:00:00', 'mid', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.375, 0.45, 0.175, '["新浪新闻"]', '齐鲁晚报·齐鲁壹点 冯子涵 世界杯开幕式表演。新华社发 北京时间7月20日，2026年美加墨世界杯决赛即将在纽约新泽西体育场打响。围绕这场巅峰对决的讨论，因一项打破传统的新规愈演愈烈：为配合国际足联安排的群星半场秀，世界杯决赛的中场休息预计将延长至约30分钟，这将超过《足球竞赛规则》规定的15分钟上限。', '法国、西班牙、美加墨', '拍世界杯的摄影记者，都有些什么特点。', '["姆巴", "夏奇拉", "亚马尔", "姆巴佩"]', '{"credibility_score": 1.0, "official_ratio": 1.0, "verified_ratio": 1.0, "plain_user_ratio": 0.0, "verification_dist": {"官方平台": 1.0}, "factors": ["well_sourced"]}', '{"key_nodes": [{"role": "初始爆料", "author": "新华社", "platform": "新浪新闻", "verification_type": "官方平台", "publish_time": "2026-07-14T11:14:29", "influence": 0.0, "title": "图说世界杯丨想当世界杯摄影记者，照片拍得好还远远不够"}], "top_influencers": [], "platform_chain": {"nodes": [{"name": "新浪新闻", "count": 9, "first_seen": "2026-07-14T11:14:29"}], "links": []}}', '2026-07-15 22:17:29', '2026-07-15 22:17:29');
