INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (8, '阿根廷庆祝晋级半决赛', 7.285, 46, 1, '2026-07-10 23:27:43', '2026-07-14 14:22:41', '2026-07-12 12:00:00', 'mid', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.452, 0.29, 0.258, '["微博", "新浪新闻", "知乎"]', '北京时间7月12日凌晨，美加墨世界杯1/4决赛继续开打，瑞士迎战阿根廷。上一轮1/8决赛上，瑞士苦战120分钟0-0闷平，最后点球大战4-3淘汰哥伦比亚，而阿根廷更惊险，在0-2落后的情况下，最终连追3球以3-2逆转晋级。本场较量关乎谁将晋级四强，属于生死之战，常规时间两队战成1-1平，加时赛阿根廷连进两球，最终瑞士1-3不敌阿根廷，止步八强。', '瑞士、埃及、美加墨', '梅西带领球队出来进行热身。', '["恩博洛", "阿尔瓦雷", "麦卡利斯", "恩多耶", "劳塔罗"]', '{"credibility_score": 0.458, "official_ratio": 0.261, "verified_ratio": 0.783, "plain_user_ratio": 0.217, "verification_dist": {"认证个人": 0.413, "官方平台": 0.261, "普通用户": 0.217, "头部认证个人": 0.109}, "factors": ["well_sourced"]}', '{"key_nodes": [{"role": "初始爆料", "author": "曾经", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-10T23:27:43", "influence": 71.8, "title": "但凡认真看过几场阿根廷队踢球就会知道，这球队踢得脏，小动作不断搞人心态，为了赢什"}, {"role": "首次官方媒体介入", "author": "欧洲足球记录者", "platform": "新浪新闻", "verification_type": "官方平台", "publish_time": "2026-07-12T07:39:10", "influence": 0.0, "title": "阿根廷队来了！"}, {"role": "首次大V发声", "author": "李平康_", "platform": "微博", "verification_type": "头部认证个人", "publish_time": "2026-07-12T11:32:24", "influence": 6.6, "title": "#瑞士 脏# 上一场热搜是阿根廷脏，现在又说瑞士脏，咱们这都玩闹呢？都是很正常的"}, {"role": "传播高峰", "author": "DeMess1Cafe", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-12T16:00:40", "influence": 395.4, "title": "阿根廷vs瑞士，赛后瑞士球员曼赞比拿到了梅西的球衣还答应给记者炫耀了😎 #阿根廷"}], "top_influencers": [{"author": "DeMess1Cafe", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-12T16:00:40", "influence": 395.4, "repost_count": 22, "like_count": 1193, "comment_co