INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (14, '警惕！暴雨预警期间别踩法律红线', 18.233, 103, 151, '2026-06-04 16:50:38', '2026-07-15 18:03:38', '2026-07-14 12:00:00', 'mid_high', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.49, 0.322, 0.187, '["人民网", "微博", "新浪新闻", "澎湃新闻", "知乎"]', '中央气象台7月15日10时继续发布暴雨黄色预警： 预计，7月15日14时至16日14时，青海东部和南部、甘肃南部、宁夏南部、四川盆地西部、河南东北部、 山东中南部 、 江苏北部、安徽北部、广东西部和南部沿海、广西大部、贵州南部、云南东部等地部分地区 有大到暴雨 ， 其中， 山东中南部、江苏北部、广西中南部、广东西南部沿海等地部分地区有大暴雨（100～240毫米）。上述部分地区伴有短时强降水（最大小时降雨量20～50毫米，局地可超过90毫米），局地有雷暴大风或冰雹等强对流天气。防御指南： 1、政府及相关部门按照职责做好防暴雨工作。', '广西、台风、贵港', '重庆永川、湖南石门、广东江门遭遇特大暴雨。', '["黄淮", "高峰", "武鸣", "周映", "杨驰"]', '{"credibility_score": 0.746, "official_ratio": 0.835, "verified_ratio": 0.942, "plain_user_ratio": 0.058, "verification_dist": {"官方平台": 0.835, "认证机构": 0.078, "普通用户": 0.058, "认证个人": 0.029}, "factors": ["high_duplicate_rate", "well_sourced"]}', '{"key_nodes": [{"role": "首次官方媒体介入", "author": "人民网－广西频道", "platform": "人民网", "verification_type": "官方平台", "publish_time": "2026-06-04T16:50:38", "influence": 0.0, "title": "贵港供电局全力筑牢高考保电安全防线"}, {"role": "初始爆料", "author": "胡飞飞", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-06T15:43:34", "influence": 0.3, "title": "广西郁江发生2026年第1号洪水，贵港水文站水位超警戒1.80米 - 知乎"}, {"role": "传播高峰", "author": "央视新闻", "platform": "微博", "verification_type": "官方平台", "publish_time": "2026-07-06T18:33:26", "influence": 7821.7, "title": "#广西洪水##安排1亿元支持广西灾后恢复#【 #广西2地洪水防御应急响应升为一级"}, {"role": "首次大V发声", "author": "大皖新闻", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-14T06:43:51", "influence": 130.8, "title": "【中央气象台发布暴雨橙色预警 辽宁、广西等地部分地区有大暴雨】14日6时，中央气"}], "top_influencers": [{"author": "央视新闻", "platform": "微博", 