INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (15, '多地摩友自发驰援广西将物资送入村', 16.353, 72, 23, '2026-06-20 09:26:26', '2026-07-15 18:02:00', '2026-07-14 12:00:00', 'mid_high', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.692, 0.288, 0.019, '["人民网", "微博", "新浪新闻", "澎湃新闻", "知乎"]', '近日，受2026年第10号台风“美莎克”持续影响，广西多地遭遇强降雨天气，部分地区引发严重洪涝灾害，防汛救灾及灾后恢复形势严峻。灾情牵动全国人心，社会各界企业迅速响应，连锁餐饮、农牧养殖、食品饮料、互联网平台、汽车制造、纺织服饰、潮玩文创等多领域品牌第一时间启动应急救援机制，通过捐款及调拨应急物资等多种方式，紧急驰援广西受灾一线，全力保障群众生活安置、一线抢险救援，精准助力灾区防汛救灾与特色产业复产，以担当汇聚起救灾的力量。以下是澎湃新闻CSR周刊对相关情况进行的汇总梳理： 连锁餐饮 ·蜜雪冰城向广西受灾地区捐赠1000万元，支援防汛救灾和产业恢复 ·喜茶再次捐赠200万元驰援广西防汛救灾 ·茉莉奶白捐赠100万元现金驰援广西洪灾救援 ·瑞幸咖啡紧急驰援抗洪救灾 ·驰援广西横州。', '广西、贵港、横州', '7月9日，记者在广西横州市马岭镇健康产业园物资接收点了解到，截至当天上午5时，该产业园已累计接收各类捐赠物资约43万件。', '["张雪", "刘宇宁", "魏大勋", "陆川", "龙卷风"]', '{"credibility_score": 0.761, "official_ratio": 0.611, "verified_ratio": 0.944, "plain_user_ratio": 0.056, "verification_dist": {"官方平台": 0.611, "认证机构": 0.194, "头部认证个人": 0.083, "认证个人": 0.056, "普通用户": 0.056}, "factors": ["well_sourced"]}', '{"key_nodes": [{"role": "首次官方媒体介入", "author": "青海日报", "platform": "人民网", "verification_type": "官方平台", "publish_time": "2026-06-20T09:26:26", "influence": 0.0, "title": "海东76吨果蔬运往地震灾区"}, {"role": "首次大V发声", "author": "荔枝新闻", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-07T13:20:55", "influence": 10083.4, "title": "【#周深捐赠物资驰援广西灾区##周深多次在灾情中极速响应#】受台风影响，广西多地"}, {"role": "初始爆料", "author": "邕江游仔", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-09T23:14:14.000001", "influence": 7.0, "title": "广西水灾，横州水灾，捐款捐赠名单（全网最全版） - 知乎"}], "top_influencers": [{"author": "荔枝新闻", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-07T13:20:55", "influence": 10083.4, "repost_count": 3173, "like_count": 20513, "comment_count": 1513, "title": "【#周深捐赠物资驰援广西灾区##周深多次在灾情中极速响应#】受台风影响，广西多地"}, {"author": "纵览新闻", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-07T17:16:57", "influence": 4287.2, "repost_count": 1640, "like_count": 8119, "comment_count": 423, "title": "【#郝熠然向广西捐赠物资#】#郝熠然驰援广西灾区#近日，广西南宁、贵港等地因台风"}, {"author": "白鹿视频", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-07T16:26:17", "influence": 3735.2, "repost_count": 783, "like_count": 8994, "comment_count": 508, "title": "【#易烊千玺驰援广西灾区#】7月7日，@中国乡村发展基金会 发文：近日，受第10"}, {"author": "中华思源工程基金会", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-08T01:57:54", "influence": 3145.3, "repost_count": 833, "like_count": 6291, "comment_count": 850, "title": "【风雨同舟 共援广西】@单依纯 携手#中华思源工程基金会#驰援广西洪灾！ 受台风"}, {"author": "碎叫", "platform": "微博", "verification_type": "头部认证个人", "publish_time": "2026-07-09T07:08:31", "influence": 2238.7, "repost_count": 638, "like_count": 4864, "comment_count": 283, "title": "辟谣，广西灾区不管是什么救援队救人收费直接报警抓人。 蓝天救援队救援不收费，更不"}], "platform_chain": {"nodes": [{"name": "人民网", "count": 16, "first_seen": "2026-06-20T09:26:26"}, {"name": "微博", "count": 23, "first_seen": "2026-07-07T13:20:55"}, {"name": "澎湃新闻", "count": 4, "first_seen": "2026-07-09T15:10:00"}, {"name": "知乎", "count": 5, "first_seen": "2026-07-09T23:14:14.000001"}, {"name": "新浪新闻", "count": 17, "first_seen": "2026-07-11T08:32:31"}], "links": [{"source": "人民网", "target": "微博", "value": 23}, {"source": "微博", "target": "澎湃新闻", "value": 4}, {"source": "澎湃新闻", "target": "知乎", "value": 5}, {"source": "知乎", "target": "新浪新闻", "value": 17}]}}', '2026-07-15 22:17:29', '2026-07-15 22:17:29');
