INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (17, '暴雨洪水来袭记住这三点避险', 9.329, 18, 0, '2026-07-10 15:32:00', '2026-07-15 15:21:00', '2026-07-14 12:00:00', 'mid', 'peak', 0.9, 0.0, 0.05, 0.9, 0.05, '当前事件报道量已接近峰值，关注度趋于稳定，处于高潮期。', 0.467, 0.3, 0.233, '["微博", "新浪新闻"]', '据中国天气网消息，今天（7月15日），“巴威”对我国影响基本结束，不过强降雨并未退场，今后三天，在南海热带扰动影响下，两广地区局地有大暴雨或特大暴雨天气，同时四川盆地至黄淮一带强降雨将持续在线，相关部门和公众要防范暴雨可能引发的次生灾害。昨天到今晨，我国降水主要集中在三片区域。其一是在辽宁东部、吉林东部，受“巴威”远距离水汽输送影响，出现暴雨或大暴雨，沈阳赛艇中心雨势最强，雨量达到563.2毫米，相当于北方很多城市全年的降水。', '广西、台风、巴威', '广西暴雨转高温，警惕午后热雷雨 #气象科普# #广西加油共渡难关# 暴雨退去，高温来袭。', '["美莎克", "武宣", "黄淮"]', '{"credibility_score": 0.725, "official_ratio": 0.5, "verified_ratio": 0.944, "plain_user_ratio": 0.056, "verification_dist": {"官方平台": 0.5, "认证个人": 0.222, "认证机构": 0.167, "普通用户": 0.056, "头部认证个人": 0.056}, "factors": ["well_sourced"]}', '{"key_nodes": [{"role": "首次官方媒体介入", "author": "知识引力场", "platform": "新浪新闻", "verification_type": "官方平台", "publish_time": "2026-07-10T15:32:00", "influence": 0.0, "title": "广西暴雨转高温，警惕午后热雷雨"}, {"role": "初始爆料", "author": "用户7874430497", "platform": "微博", "verification_type": "普通用户", "publish_time": "2026-07-12T22:00:41", "influence": 0.0, "title": "广西暴雨加洪水太惨了，还有台风别来东北，我害怕我也不会游泳，但是怀念居家办公的日"}, {"role": "首次大V发声", "author": "广西气象", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-14T19:30:01", "influence": 0.9, "title": "预计未来三天，广西多降雨天气，在降雨的作用下，高温渐缓，不过由于空气湿度较大，体"}, {"role": "传播高峰", "author": "中国气象爱好者", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-15T11:53:54.000001", "influence": 165.5, "title": "#天气##暴雨##广西洪水# 广西最近与台风暴雨杠上了！月初美莎克极端暴雨才停没"}], "top_influencers": [{"author": "中国气象爱好者", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-15T11:53:54.