INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (24, '国产动力舟桥救援广西学子脱险', 5.832, 57, 43, '2026-07-07 22:38:00', '2026-07-13 22:10:01', '2026-07-12 12:00:00', 'mid', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.592, 0.408, 0.0, '["人民网", "微博", "新浪新闻", "澎湃新闻", "知乎"]', '单次可载五百余人，救援人员携“水上救援航母”转运广西贵港被洪水围困的学生 近日，台风暴雨引发广西贵港部分地区发生内涝，贵港市广西物流职业技术学院6000余名学生被困。7月8日17时，中国安能组装应急动力舟桥前往该学校转移被困学生。队员介绍应急动力舟桥自带动力、架设快速、机动灵活，可快速搭建形成水上作业平台，单次可运载500余人，被誉为“水上救援航母”。', '广西、贵港、舟桥', '7月7日晚，广西贵港市教育局通报该市城区部分学校物资保障情况及学生安置情况，全文如下： 关于贵港市城区高中学校物资保障及学生安置情况的通报受近期台风影响，我市城区部分学校出现严重内涝，其中贵港市高级中学、达开高级中学、大将高级中学等高中校园积水较深，导致师生出行受阻，学习生活受到一定影响。', '["廖小华", "高喊", "李蕊", "武警官兵", "唐燕丽"]', '{"credibility_score": 0.73, "official_ratio": 0.684, "verified_ratio": 0.93, "plain_user_ratio": 0.07, "verification_dist": {"官方平台": 0.684, "认证机构": 0.14, "普通用户": 0.07, "认证个人": 0.053, "头部认证个人": 0.053}, "factors": ["high_duplicate_rate", "well_sourced"]}', '{"key_nodes": [{"role": "首次官方媒体介入", "author": "澎湃新闻", "platform": "澎湃新闻", "verification_type": "官方平台", "publish_time": "2026-07-07T22:38:00", "influence": 0.0, "title": "广西贵港市多所高中严重内涝学生出行受阻，多部门联动确保学生安全和物资保障_直击现"}, {"role": "首次大V发声", "author": "百姓关注", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-09T13:15:47.999999", "influence": 4447.9, "title": "【“它也想哭了，累得动不了” 广东蓝天#救援队转移学生顺手捞上无助小猪# 】7月"}, {"role": "传播高峰", "author": "央视新闻", "platform": "微博", "verification_type": "官方平台", "publish_time": "2026-07-09T18:00:00", "influence": 9989.2, "title": "【硬核救援！#救援航母出现那一刻安全感拉满#】#救援航母上响起歌唱祖国# 近日，"}, {"role": "初始爆料", "author": "LECOME乐康优品", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-10T10:06:16", "influence": 0.3, "title": "贵港1.2万师生被困“孤岛”，解放军冲锋舟劈开洪水：灾难面前的“中国速度”是怎么"}], "top_influencers": [{"author": "央视新闻", "platform": "微博", "verification_type": "官方平台", "publish_time": "2026-07-09T18:00:00", "influence": 9989.2, "repost_count": 1916, "like_count": 24739, "comment_count": 1303, "title": "【硬核救援！#救援航母出现那一刻安全感拉满#】#救援航母上响起歌唱祖国# 近日，"}, {"author": "央视新闻", "platform": "微博", "verification_type": "官方平台", "publish_time": "2026-07-09T10:21:12", "influence": 9906.9, "repost_count": 1311, "like_count": 26883, "comment_count": 1062, "title": "【#当救援航母驶入洪水校园#[心]】#动力舟桥洪水中化身生命方舟# 近日，广西贵"}, {"author": "绿茶发言大赏", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-10T20:03:27", "influence": 6381.2, "repost_count": 581, "like_count": 18819, "comment_count": 309, "title": "感觉这张照片可以上《感动中国》了[苦涩] 广西贵港洪灾区蓝天救援队在转移贵港高中"}, {"author": "中国新闻网", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-09T19:09:13", "influence": 6346.1, "repost_count": 907, "like_count": 16407, "comment_count": 1034, "title": "【致敬！#贵港救援人员席地而坐冒雨吃饭#】广西贵港一线救援人员席地而坐，在雨中休"}, {"author": "秦祎墨", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-11T13:40:39", "influence": 5182.4, "repost_count": 1694, "like_count": 11523, "comment_count": 63, "title": "最近有两个新闻： 第一个新闻：广西洪水，有很多学生被困学校，转以后其实接走的都不"}], "platform_chain": {"nodes": [{"name": "澎湃新闻", "count": 7, "first_seen": "2026-07-07T22:38:00"}, {"name": "微博", "count": 18, "first_seen": "2026-07-09T09:33:00"}, {"name": "人民网", "count": 6, "first_seen": "2026-07-09T17:56:24"}, {"name": "新浪新闻", "count": 20, "first_seen": "2026-07-10T09:00:00"}, {"name": "知乎", "count": 5, "first_seen": "2026-07-10T10:06:16"}], "links": [{"source": "澎湃新闻", "target": "微博", "value": 18}, {"source": "微博", "target": "人民网", "value": 6}, {"source": "人民网", "target": "新浪新闻", "value": 20}, {"source": "新浪新闻", "target": "知乎", "value": 5}]}}', '2026-07-15 22:17:29', '2026-07-15 22:17:29');
