INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (26, '广西洪水肆虐子弟兵星夜驰援', 5.585, 16, 6, '2026-07-12 21:58:45', '2026-07-15 17:08:00', '2026-07-13 12:00:00', 'mid', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.87, 0.13, 0.0, '["微博", "新浪新闻"]', '青岛16勇士驰援广西两天转运200余村民 【青岛故事｜#青岛16勇士驰援广西两天转运200余村民#，#青岛16名志愿者跨两千余里驰援广西#】7月9日，青岛胶州的16名勇士跨越2300公里，驰援受台风 “美莎克” 影响遭遇极端强降雨的广西。截至7月12日下午，救援队已转运当地200余人，重点转运患病群众就医。当地高温潮湿环境让队员们身生痱子、衣物湿透，却收获当地群众送龙眼、老人致谢等暖心瞬间。', '广西、江西、贵港', '广西洪水肆虐子弟兵星夜驰援 #中国海军奋进新时代[超话]# 广西洪水肆虐，子弟兵星夜驰援。', '["李宗明", "陆军", "武警官兵"]', '{"credibility_score": 0.835, "official_ratio": 0.75, "verified_ratio": 1.0, "plain_user_ratio": 0.0, "verification_dist": {"官方平台": 0.75, "认证机构": 0.188, "认证个人": 0.062}, "factors": ["well_sourced"]}', '{"key_nodes": [{"role": "初始爆料", "author": "土楼先生", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-12T21:58:45", "influence": 0.0, "title": "为扛楼战神波哥点赞。素有扛楼战神之称的波哥，主动奔赴受灾村落。进村道路被洪水淤泥"}, {"role": "首次官方媒体介入", "author": "北锋迷彩情报站", "platform": "新浪新闻", "verification_type": "官方平台", "publish_time": "2026-07-13T06:10:44", "influence": 0.0, "title": "广西洪水肆虐子弟兵星夜驰援"}, {"role": "首次大V发声", "author": "央视军事报道", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-13T20:55:54", "influence": 0.8, "title": "#抢险救援 子弟兵在行动#经过几天的救援，广西横州洪水逐步减退。今天，解放军和武"}], "top_influencers": [{"author": "央视军事报道", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-13T20:55:54", "influence": 0.8, "repost_count": 0, "like_count": 1, "comment_count": 1, "title": "#抢险救援 子弟兵在行动#经过几天的救援，广西横州洪水逐步减退。今天，解放军和武"}], "platform_chain": {"nodes": [{"name": "微博", "count": 4, "first_seen": "2026-07-12T21:58:45"}, {"name": "新浪新闻", "count": 12, "first_