fluence": 630.5, "repost_count": 60, "like_count": 1705, "comment_count": 118, "title": "【#广西辟谣贵港养蛇场有蛇出逃#：不存在蛇外逃、扩散的风险情况】#广西因灾死亡6"}, {"author": "費德外科", "platform": "微博", "verification_type": "普通用户", "publish_time": "2026-07-15T15:17:18", "influence": 32.1, "repost_count": 25, "like_count": 22, "comment_count": 1, "title": "南方周末这篇六蓝水库溃口前24h的报道在chinadigitaltimes有存档"}, {"author": "健康与自", "platform": "微博", "verification_type": "头部认证个人", "publish_time": "2026-07-12T00:11:37", "influence": 3.6, "repost_count": 0, "like_count": 12, "comment_count": 0, "title": "#广西洪水#2026年7月，受台风“美莎克”影响，广西遭遇历史罕见极端暴雨，多条"}, {"author": "是幸运的千问哇", "platform": "微博", "verification_type": "头部认证个人", "publish_time": "2026-07-12T20:52:55.000001", "influence": 3.3, "repost_count": 0, "like_count": 11, "comment_count": 0, "title": "#台风美莎克#警惕！受台风“美莎克”残余环流影响，广西多地正遭遇历史罕见的持续性"}], "platform_chain": {"nodes": [{"name": "微博", "count": 17, "first_seen": "2026-07-07T20:35:58"}, {"name": "澎湃新闻", "count": 4, "first_seen": "2026-07-08T10:10:00"}, {"name": "知乎", "count": 3, "first_seen": "2026-07-09T09:40:37"}, {"name": "人民网", "count": 1, "first_seen": "2026-07-09T14:37:40"}, {"name": "新浪新闻", "count": 3, "first_seen": "2026-07-09T16:02:28"}], "links": [{"source": "微博", "target": "澎湃新闻", "value": 4}, {"source": "澎湃新闻", "target": "知乎", "value": 3}, {"source": "知乎", "target": "人民网", "value": 1}, {"source": "人民网", "target": "新浪新闻", "value": 3}]}}', '2026-07-15 22:17:29', '2026-07-15 22:17:29');
