INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (29, '美联储为何保留加息选项', 37.353, 62, 3, '2026-07-11 12:00:00', '2026-07-15 17:20:19', '2026-07-14 12:00:00', 'high', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.643, 0.238, 0.119, '["微博", "新浪新闻", "知乎"]', '（来源：今日金价行情） 周三(7月15日)亚市早盘，现货黄金价格维持坚挺走势，金价目前交投在4055美元/盎司附近。上一交易日，受疲软美国CPI数据影响，金价暴涨逾50美元。FXStreet分析师Christian Borjon Valencia最新撰文，对金价走势进行分析。', '美国、美伊、中东', '汇通网 汇通财经APP讯—— 本月上旬，美元走弱带动黄金短暂走高，当时市场普遍认为上涨行情会延续，但美联储 公开市场委员会（FOMC）会议纪要发布之后局势逆转。', '["白银", "特朗普", "高盛", "沃勒", "黄金周"]', '{"credibility_score": 0.485, "official_ratio": 0.274, "verified_ratio": 0.823, "plain_user_ratio": 0.177, "verification_dist": {"认证个人": 0.371, "官方平台": 0.274, "头部认证个人": 0.177, "普通用户": 0.177}, "factors": ["well_sourced"]}', '{"key_nodes": [{"role": "首次大V发声", "author": "Hydrocracking大地采集者", "platform": "微博", "verification_type": "头部认证个人", "publish_time": "2026-07-13T15:12:00", "influence": 1.2, "title": "#金价# 黄金跌破4050美元，跌超1.6%——这回不是中东炮火吓的，而是美国通"}, {"role": "首次官方媒体介入", "author": "实时速报", "platform": "新浪新闻", "verification_type": "官方平台", "publish_time": "2026-07-13T20:06:20", "influence": 0.0, "title": "金价走势取决于CPI数据、沃什表态以及霍尔木兹海峡地缘风险"}, {"role": "初始爆料", "author": "华尔街之犬-老狼", "platform": "微博", "verification_type": "普通用户", "publish_time": "2026-07-13T20:21:01", "influence": 0.0, "title": "中东冲突推高油价，引发通胀担忧，美联储9月加息概率飙升，美元强势直接压制了黄金。"}, {"role": "传播高峰", "author": "要不我来试试水", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-14T21:04:15", "influence": 72.3, "title": "美国的6月CPI环比下降0.4% 同比增长3.5% 美国短期利率期货大幅跳涨，交"}], "top_influencers": [{"author": "要不我来试试水", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-14T21:04:15", "influence"