INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (34, '国际油价13日大幅上涨', 8.969, 42, 36, '2026-06-24 00:00:00', '2026-07-15 16:24:22', '2026-07-13 12:00:00', 'mid', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.65, 0.35, 0.0, '["微博", "新浪新闻", "澎湃新闻", "知乎"]', '苹果博通签超300亿美元芯片大单油价飙升金价大跌 【#苹果博通签超300亿美元芯片大单##油价飙升金价大跌#】当地时间周三，美国总统特朗普在北约峰会上说，他认为美伊谅解备忘录“已终结”，中东局势再度紧张，油价飙升，美国三大股指当天收盘走势分化，道指下跌1.09%，标普500指数下跌0.28%，纳指小幅上涨0.2%。板块方面，材料和金融板块跌幅较大，能源和科技板块则是普遍上涨，热门中概股多数上涨，纳斯达克中国金龙指数上涨2.05%。阿里巴巴涨超11%，爱奇艺涨超5%。', '美国、伊朗、美伊', '美股三大股指周二集体收跌，标普500指数跌1.44%，纳指跌2.21%。', '["布伦特", "白银", "特斯拉", "亚马逊", "埃克森"]', '{"credibility_score": 0.657, "official_ratio": 0.548, "verified_ratio": 0.929, "plain_user_ratio": 0.071, "verification_dist": {"官方平台": 0.548, "认证机构": 0.167, "认证个人": 0.119, "头部认证个人": 0.095, "普通用户": 0.071}, "factors": ["high_duplicate_rate", "well_sourced"]}', '{"key_nodes": [{"role": "首次官方媒体介入", "author": "澎湃新闻", "platform": "澎湃新闻", "verification_type": "官方平台", "publish_time": "2026-06-24T00:00:00", "influence": 0.0, "title": "美股三大股指集体收跌：纳指跌2.21%，大型科技股多数下跌_牛市点线面_澎湃新闻"}, {"role": "初始爆料", "author": "币世界忠本聪", "platform": "微博", "verification_type": "普通用户", "publish_time": "2026-07-07T01:32:30.999999", "influence": 136.4, "title": "周一美股指，纳斯达克指数盘中涨幅1.2%，标普500指数涨幅0.6%，黄金跌幅0"}, {"role": "首次大V发声", "author": "红星新闻", "platform": "微博", "verification_type": "认证机构", "publish_time": "2026-07-08T08:06:20", "influence": 60.4, "title": "【#一觉醒来黄金又跌了#】#黄金又跌破4100美元了# 北京时间7月8日，国际油"}, {"role": "传播高峰", "author": "提车战法", "platform": "微博", "verification_type": "认证个人", "publish_time": "2026-07-14T06:05:02", "influence": 294.1, "title": "#东方财富##股票#【全球市场：美股三大指数集体收跌 存储概念股普跌 国际油价大"}], "top_influencers": [{"author": "提车战法", "pl