INSERT INTO events (event_id, title, heat, report_count, duplicate_count, time_start, time_end, event_time, risk_level, stage, confidence, prob_latent, prob_growth, prob_peak, prob_decline, analysis, positive, neutral, negative, sources, summary, location, cause, people, authenticity, propagation, created_at, updated_at) VALUES (39, 'AI时代码农升级导演，认知升维决定未来', 8.564, 67, 77, '2026-06-09 00:00:00', '2026-07-15 18:43:47', '2026-07-10 12:00:00', 'mid', 'decline', 0.9, 0.0, 0.0, 0.1, 0.9, '当前事件报道数量持续下降，公众关注度减弱，处于衰退期。', 0.424, 0.358, 0.218, '["微博", "新浪新闻", "澎湃新闻", "知乎"]', '7月6日，美国AI初创企业Anthropic表示，已识别出旗下大模型Claude内部使用的一个小型工作空间，在该空间中，Claude可激活与其输出无关的概念和计算。Anthropic称，这一结构与人类有意识地获取思想的方式有着相似之处，它让我们得以窥见Claude在思考却未说出的内容。Anthropic将之命名为“J-空间”（J-Space），名称来源于用于发现它的一种数学技术——雅可比（Jacobian）。', '中国、美国、东西', '6月9日凌晨，苹果公司一年一度的全球开发者大会（WWDC）开幕，时隔两年，苹果再次集中发布AI战略，推出了新一代Apple智能以及重构过的语音助手Siri AI，并推出迭代版本 iOS 27、iPadOS 27、macOS 27等全系操作系统。', '["阿里", "高峰", "李林", "唐杰", "卡兹克"]', '{"credibility_score": 0.502, "official_ratio": 0.478, "verified_ratio": 0.687, "plain_user_ratio": 0.313, "verification_dist": {"官方平台": 0.478, "普通用户": 0.313, "头部认证个人": 0.134, "认证个人": 0.075}, "factors": ["high_duplicate_rate", "well_sourced"]}', '{"key_nodes": [{"role": "首次官方媒体介入", "author": "澎湃新闻", "platform": "澎湃新闻", "verification_type": "官方平台", "publish_time": "2026-06-09T00:00:00", "influence": 0.0, "title": "苹果打出最强AI战略：Siri全新升级，库克称“生涯高光时刻之一”，但中国用户还"}, {"role": "初始爆料", "author": "零度解说", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-06-25T22:19:30", "influence": 23.8, "title": "Claude 被开源了？Qwythos-9B 突然发布！无审查、104万上下文、"}, {"role": "传播高峰", "author": "大卡", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-01T02:39:43", "influence": 761.1, "title": "我觉得这件事情可以从两个问题的角度来讨论：1. 结合最近几个月发生的事情，这个事"}, {"role": "首次大V发声", "author": "极客公园", "platform": "知乎", "verification_type": "头部认证个人", "publish_time": "2026-07-03T17:35:08", "influence": 1.5, "title": "Anthropic 公告里最刺眼的 3 个名字，有 1 家中国模型 - 知乎"}], "top_influencers": [{"author": "大卡", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-01T02:39:43", "influence": 761.1, "repost_count": 0, "like_count": 1967, "comment_count": 342, "title": "我觉得这件事情可以从两个问题的角度来讨论：1. 结合最近几个月发生的事情，这个事"}, {"author": "赵泠", "platform": "知乎", "verification_type": "头部认证个人", "publish_time": "2026-07-08T13:05:38.999999", "influence": 62.0, "repost_count": 0, "like_count": 200, "comment_count": 4, "title": "显然，这是 Anthropic 的某些员工在拿大语言模型的正常举动制造噱头，然后"}, {"author": "下雨天打伞", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-03T18:26:31", "influence": 58.9, "repost_count": 0, "like_count": 173, "comment_count": 14, "title": "cc这明显投毒了，而且agent是有能力直接删你系统，甚至收集你的账号远程登录服"}, {"author": "Kris谭", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-08T13:40:47", "influence": 39.6, "repost_count": 0, "like_count": 117, "comment_count": 9, "title": "这就是Logit Lens的变体，与此同时线性映射进行干预本来就必然会改变一个事"}, {"author": "原地爆炸的熊猫", "platform": "知乎", "verification_type": "普通用户", "publish_time": "2026-07-11T02:30:04.000001", "influence": 28.6, "repost_count": 0, "like_count": 72, "comment_count": 14, "title": "因为Claude code并不比opencode优秀。我使用opencode最重"}], "platform_chain": {"nodes": [{"name": "澎湃新闻", "count": 4, "first_seen": "2026-06-09T00:00:00"}, {"name": "知乎", "count": 22, "first_seen": "2026-06-25T22:19:30"}, {"name": "新浪新闻", "count": 16, "first_seen": "2026-07-06T12:04:45"}, {"name": "微博", "count": 8, "first_seen": "2026-07-10T05:37:51"}], "links": [{"source": "澎湃新闻", "target": "知乎", "value": 22}, {"source": "知乎", "target": "新浪新闻", "value": 16}, {"source": "新浪新闻", "target": "微博", "value": 8}]}}', '2026-07-15 22:17:29', '2026-07-15 22:17:29');
